    // 4. Add all observers to watch target
    for (const auto& observer : observers) {
        graph->addObserver(target.get(), observer.get());
    }

    // 5. Notify target
    graph->notify(target.get());

    // 6. Count notifications and verify all observers were notified
    int totalCallCount = 0;
    bool allNotified = true;

    for (const auto& observer : observers) {
        int callCount = observer->getCallCount();
        totalCallCount += callCount;
        if (callCount == 0 || !observer->wasChanged()) {
