    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

RollbackObservation test_observer_state_rollback() {
    // 1. Create RecordingNode instances
    RecordingNode sensor1;
    RecordingNode sensor2;
    RecordingNode observer;

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::instance();

    // 3. Register nodes
    graph.registerNode(&sensor1);
    graph.registerNode(&sensor2);
    graph.registerNode(&observer);

    // 4. Set up initial dependency
    graph.addDependency(&observer, &sensor1);

    // 5. Save node state for rollback
    auto rollback = graph.saveNodeState(&observer);

    // 6. Replace dependencies transactionally
    graph.replaceDependencies(&observer, {&sensor2});

    // 7. Trigger notification on second sensor
    graph.notifyObservers(&sensor2);

    // 8. Record notification count after second binding
    int notificationsAfterSecondBinding = observer.notificationCount();

    // 9. Execute rollback
    rollback();

    // 10. Trigger notification on first sensor
    graph.notifyObservers(&sensor1);

    // 11. Record notification count after rollback
    int notificationsAfterRollback = observer.notificationCount();

    // 12. Return notification counts
    return {notificationsAfterSecondBinding, notificationsAfterRollback};
}

