    bool allocationBlockedAtLimit = false;

    {
        StackMonitor::StackGuard<SBOConfig::MAX_SBO_STACK_USAGE> guard;
        guardSucceeded = guard.success();
        allocationBlockedAtLimit = !StackMonitor::canAllocate<64>();
